                                  ))
                                 .FirstOrDefaultAsync(ct);

            if (categoryDto == null)
            {
                return ResponseWrapper<CategoryDto>.Fail("Category not found.");
            }

            return ResponseWrapper<CategoryDto>.Success(categoryDto);
        }
    }
}
