    public abstract class DomainEvent : IDomainEvent
    {
        protected DomainEvent()
        {
            DateOccurred = DateTimeOffset.UtcNow;
        }

        /// <summary>
        /// Flag indicating whether the event has been published.
        /// </summary>
        public bool IsPublished { get; set; }

        /// <summary>
